var e=[{id:`L2_1`,type:`dialog`,speaker:`PLAYER_SPORTS_NPC_BLUE`,text:{KOREA:`이번 경기는 장애물 달리기네.`,JPN:`今回の試合は障害物競走か。`,ENG:`This time, it's an obstacle race.`,TWN:`這場比賽是障礙賽跑。`},stage:{bg:`SPORTSGROUND`,bgm:`THEMA_ACADEMY`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}},sfx:`FX_CUTSCEN_CROWD_NOISE`},{id:`L3_1`,type:`dialog`,speaker:`PLAYER_SPORTS_NPC_BLUE`,text:{KOREA:`우리 팀에선 누가 주전으로 나가지?`,JPN:`うちのチームは誰がレギュラーになるんだ？`,ENG:`Who should go out as a runner?`,TWN:`我們隊誰當主力？`},stage:{bg:`SPORTSGROUND`,bgm:`THEMA_ACADEMY`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L4_1`,type:`dialog`,speaker:`PLAYER_SPORTS_NPC_BLUE`,text:{KOREA:`어이! 혹시 추천하고 싶은 사람 있어?`,JPN:`なあ！　おすすめしたい人はいる？`,ENG:`Hey! Anyone you want to recommend?`,TWN:`唉！你有想推薦的人嗎？`},stage:{bg:`SPORTSGROUND`,bgm:`THEMA_ACADEMY`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L5_1`,type:`dialog`,speaker:`RULER_JUNIOR_NULL_NULL`,text:{KOREA:`저요! 저요!`,JPN:`私！　私がやる！`,ENG:`Me! Me!`,TWN:`我！我！`},stage:{bg:`SPORTSGROUND`,bgm:`THEMA_ACADEMY`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`RULER_JUNIOR_NULL_NULL`,face:`UNIT_PRIDE`},R:null}}},{id:`L6_1`,type:`dialog`,speaker:`RULER_JUNIOR_NULL_NULL`,text:{KOREA:`제가 주전으로 달리고 싶어요!`,JPN:`私がレギュラーをやりたい！`,ENG:`I want to go out as a runner!`,TWN:`我想當主力！`},stage:{bg:`SPORTSGROUND`,bgm:`THEMA_ACADEMY`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`RULER_JUNIOR_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L8_1`,type:`dialog`,speaker:`PLAYER_SPORTS_NPC_BLUE`,text:{KOREA:`흐음, 역시 다들 임시 편입생에게 맡길 생각인가 보네.`,JPN:`うーん、やっぱりみんな臨時編入生に任せる気か。`,ENG:`Hmm. I guess everyone wants the temporary transfer student.`,TWN:`呃嗯，看來大家都想讓臨時插班生出戰呢。`},stage:{bg:`SPORTSGROUND`,bgm:`THEMA_ACADEMY`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`RULER_JUNIOR_NULL_NULL`,face:`UNIT_SURPRISE`},R:null}}},{id:`L9_1`,type:`dialog`,speaker:`PLAYER_SPORTS_NPC_BLUE`,text:{KOREA:`하긴, 실력이 대단했으니까.`,JPN:`確かに、実力はすごかったから。`,ENG:`No surprise. She was really great.`,TWN:`也是，她確實很了不起。`},stage:{bg:`SPORTSGROUND`,bgm:`THEMA_ACADEMY`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`RULER_JUNIOR_NULL_NULL`,face:`UNIT_SURPRISE`},R:null}}},{id:`L10_1`,type:`dialog`,speaker:`RULER_JUNIOR_NULL_NULL`,text:{KOREA:`저기, 나도......`,JPN:`あの、私も……`,ENG:`Excuse me, I want to...`,TWN:`那個，我也……`},stage:{bg:`SPORTSGROUND`,bgm:`THEMA_ACADEMY`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`RULER_JUNIOR_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L11_1`,type:`dialog`,speaker:`RULER_JUNIOR_NULL_NULL`,text:{KOREA:`......`,JPN:`……`,ENG:`......`,TWN:`……`},stage:{bg:`SPORTSGROUND`,bgm:`THEMA_ACADEMY`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`RULER_JUNIOR_NULL_NULL`,face:`UNIT_DESPAIR`},R:null}}},{id:`L14_1`,type:`dialog`,speaker:`POLEARM_JUNIOR_NULL_NULL`,text:{KOREA:`괜찮아...... 너무 실망하지 마.`,JPN:`大丈夫……あまりガッカリしないで。`,ENG:`It's okay... Don't be disappointed.`,TWN:`沒關係……你別太失望。`},stage:{bg:`SPORTSGROUND`,bgm:`THEMA_ACADEMY`,filter:`NCFT_NORMAL`,slots:{L:{char_id:`RULER_JUNIOR_NULL_NULL`,face:`UNIT_DESPAIR`},C:null,R:{char_id:`POLEARM_JUNIOR_NULL_NULL`,face:`UNIT_IDLE`}}}},{id:`L15_1`,type:`dialog`,speaker:`POLEARM_JUNIOR_NULL_NULL`,text:{KOREA:`네가 선수로 나가지 않아도, 저 언니라면 잘 해낼 거야.`,JPN:`君が選手として出なくても、あのお姉さんがいればきっと大丈夫。`,ENG:`You don't have to play as a runner in this game. She'll do great.`,TWN:`即使你不參賽，那個姐姐一定也能做到。`},stage:{bg:`SPORTSGROUND`,bgm:`THEMA_ACADEMY`,filter:`NCFT_NORMAL`,slots:{L:{char_id:`RULER_JUNIOR_NULL_NULL`,face:`UNIT_DESPAIR`},C:null,R:{char_id:`POLEARM_JUNIOR_NULL_NULL`,face:`UNIT_IDLE`}}}},{id:`L16_1`,type:`dialog`,speaker:`RULER_JUNIOR_NULL_NULL`,text:{KOREA:`으응! 네 말이 맞아!`,JPN:`うん！　そのとおりだね！`,ENG:`Y-yeah! You're right!`,TWN:`嗯嗯！你說的沒錯！`},stage:{bg:`SPORTSGROUND`,bgm:`THEMA_ACADEMY`,filter:`NCFT_NORMAL`,slots:{L:{char_id:`RULER_JUNIOR_NULL_NULL`,face:`UNIT_IDLE`},C:null,R:{char_id:`POLEARM_JUNIOR_NULL_NULL`,face:`UNIT_IDLE`}}}},{id:`L17_1`,type:`dialog`,speaker:`RULER_JUNIOR_NULL_NULL`,text:{KOREA:`그럼 나도 최선을 다해서 상대 팀 선수를 방해해야지.`,JPN:`じゃあ、私も全力で相手チームの選手を妨害する。`,ENG:`I'll just do my best to interfere with the opposing team's runner.`,TWN:`那我也得盡全力妨礙對方隊伍的選手才是。`},stage:{bg:`SPORTSGROUND`,bgm:`THEMA_ACADEMY`,filter:`NCFT_NORMAL`,slots:{L:{char_id:`RULER_JUNIOR_NULL_NULL`,face:`UNIT_IDLE`},C:null,R:{char_id:`POLEARM_JUNIOR_NULL_NULL`,face:`UNIT_IDLE`}}}},{id:`L18_1`,type:`dialog`,speaker:`RULER_JUNIOR_NULL_NULL`,text:{KOREA:`기다려! 쓸 만한 물건들이 있는지 찾아 보고 올게!`,JPN:`待っててね！　使えそうな物があるか探してくる！`,ENG:`Wait here! I'll see if I can find something useful for the game!`,TWN:`等我一下！我去找找有沒有能用的東西！`},stage:{bg:`SPORTSGROUND`,bgm:`THEMA_ACADEMY`,filter:`NCFT_NORMAL`,slots:{L:{char_id:`RULER_JUNIOR_NULL_NULL`,face:`UNIT_LAUGH`},C:null,R:{char_id:`POLEARM_JUNIOR_NULL_NULL`,face:`UNIT_IDLE`}}}}];export{e as default};